import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    setClientData(null);
    window.location.reload(); 
  };

  return (
    <div className="home-page">

      {/* Hero Section */}
      <header 
        className="py-5 text-white" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '60vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center'
        }}
      >
        <div className="container text-center">
          <div className="row justify-content-center">
            <div className="col-lg-8">
              <div className="mb-4">
                 <span style={{ fontSize: '50px' }}>💻</span> {/* Header Emoji */}
              </div>
              <h1 className="display-3 fw-bold mb-3">Web Development</h1>
              <p className="lead fs-4 mb-4 opacity-75">Professional services by talented student freelancers.</p>
              <Link to="/services" className="btn btn-warning btn-lg px-5 fw-bold shadow">Explore Services</Link>
            </div>
          </div>
        </div>
      </header>

      {/* Features Cards Section with Emojis */}
      <section className="py-5 bg-light">
        <div className="container">
          <div className="row text-center">
            
            {/* Card 1 */}
            <div className="col-md-4 mb-4">
              <div className="card shadow-sm h-100 border-0 rounded-4 p-4 transition-hover">
                <div className="card-body">
                  <div className="mb-3" style={{ fontSize: '40px' }}>🛡️</div>
                  <h5 className="fw-bold text-primary">Secure Payments</h5>
                  <p className="text-muted">Safe and reliable transactions for every project.</p>
                </div>
              </div>
            </div>

            {/* Card 2 */}
            <div className="col-md-4 mb-4">
              <div className="card shadow-sm h-100 border-0 rounded-4 p-4 transition-hover">
                <div className="card-body">
                  <div className="mb-3" style={{ fontSize: '40px' }}>🎓</div>
                  <h5 className="fw-bold text-primary">Verified Students</h5>
                  <p className="text-muted">Work with skilled and verified student experts.</p>
                </div>
              </div>
            </div>

            {/* Card 3 */}
            <div className="col-md-4 mb-4">
              <div className="card shadow-sm h-100 border-0 rounded-4 p-4 transition-hover">
                <div className="card-body">
                  <div className="mb-3" style={{ fontSize: '40px' }}>⚡</div>
                  <h5 className="fw-bold text-primary">Fast Delivery</h5>
                  <p className="text-muted">Get your web projects completed on time.</p>
                </div>
              </div>
            </div>

          </div>
        </div>
      </section>

      {/* Map Section */}
      <section id="contact" className="py-5 bg-white">
        <div className="container py-5 text-center">
          <h2 className="fw-bold mb-5">📍 Our Location (Nashik)</h2>
          <div className="row justify-content-center">
            <div className="col-lg-10">
              <div className="shadow-lg rounded-4 overflow-hidden" style={{ height: '400px' }}>
                <iframe
                  title="Google Map"
                  src="https://www.google.com"
                  width="100%"
                  height="100%"
                  style={{ border: 0 }}
                  allowFullScreen=""
                  loading="lazy"
                ></iframe>
              </div>
            </div>
          </div>
        </div>
      </section>

      <footer className="py-4 bg-dark text-white text-center">
        <p className="mb-0">&copy; 2026 Student Freelancer Marketplace | Nashik</p>
      </footer>

    </div>
  );
}

export default Home;
